import { promises as fs } from 'fs';
import { getSwarmState, emptySwarmState } from '@/app/api/swarm/route';
import { resolveStateFilePath, getDefaultProject } from '@/lib/projects';

export async function GET(request: Request) {
  const searchParams = new URL(request.url).searchParams;
  let projectId: string | null = searchParams.get('project');

  // Fallback to first available project if no param provided
  if (!projectId) {
    projectId = await getDefaultProject();
  }

  const encoder = new TextEncoder();
  let watchInterval: ReturnType<typeof setInterval> | null = null;
  let keepaliveInterval: ReturnType<typeof setInterval> | null = null;
  let streamClosed = false;
  let lastMtime = 0;

  const stream = new ReadableStream({
    async start(controller) {
      const cleanup = () => {
        streamClosed = true;
        if (watchInterval) {
          clearInterval(watchInterval);
          watchInterval = null;
        }
        if (keepaliveInterval) {
          clearInterval(keepaliveInterval);
          keepaliveInterval = null;
        }
        try {
          controller.close();
        } catch {
          // Controller may already be closed
        }
      };

      if (request.signal.aborted) {
        cleanup();
        return;
      }

      request.signal.addEventListener('abort', cleanup);

      // If no project could be resolved, send an error event and close
      if (!projectId) {
        controller.enqueue(
          encoder.encode(`data: {"error": "No projects found"}\n\n`)
        );
        cleanup();
        return;
      }

      const stateFilePath = resolveStateFilePath(projectId);

      // Send initial state immediately on connection
      try {
        let initialState;
        try {
          initialState = await getSwarmState(projectId);
        } catch (err) {
          const msg = err instanceof Error ? err.message : String(err);
          if (msg.includes('ENOENT') || msg.includes('no such file')) {
            initialState = emptySwarmState();
          } else {
            throw err;
          }
        }
        const event = `data: ${JSON.stringify(initialState)}\n\n`;
        controller.enqueue(encoder.encode(event));

        // Record the current mtime so we only emit on actual changes
        try {
          const stats = await fs.stat(stateFilePath);
          lastMtime = stats.mtimeMs;
        } catch {
          // State file may not exist yet — start with mtime 0
        }
      } catch (error) {
        console.error('[SwarmStream] Error sending initial state:', error);
        controller.enqueue(
          encoder.encode(`data: {"error": "Failed to read initial state"}\n\n`)
        );
      }

      // Capture projectId for use in closures (guaranteed non-null at this point)
      const resolvedProjectId = projectId;

      // Poll for state file changes every second
      watchInterval = setInterval(async () => {
        if (streamClosed) return;

        try {
          let stats;
          try {
            stats = await fs.stat(stateFilePath);
          } catch {
            // State file doesn't exist yet — skip this poll cycle silently
            return;
          }
          const currentMtime = stats.mtimeMs;

          if (currentMtime !== lastMtime) {
            lastMtime = currentMtime;
            const updatedState = await getSwarmState(resolvedProjectId);
            const event = `data: ${JSON.stringify(updatedState)}\n\n`;
            controller.enqueue(encoder.encode(event));
          }
        } catch (error) {
          console.error('[SwarmStream] Error watching state file:', error);
          if (!streamClosed) {
            controller.enqueue(
              encoder.encode(`data: {"error": "Failed to read state file"}\n\n`)
            );
          }
        }
      }, 1000);

      // Send keepalive comment every 30 seconds to prevent proxy timeouts
      keepaliveInterval = setInterval(() => {
        if (!streamClosed) {
          try {
            controller.enqueue(encoder.encode(': keepalive\n\n'));
          } catch {
            // Stream may be closed
          }
        }
      }, 30000);
    },

    cancel() {
      // Client disconnected — cleanup handled via abort signal or here
      streamClosed = true;
      if (watchInterval) {
        clearInterval(watchInterval);
        watchInterval = null;
      }
      if (keepaliveInterval) {
        clearInterval(keepaliveInterval);
        keepaliveInterval = null;
      }
    },
  });

  return new Response(stream, {
    headers: {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive',
    },
  });
}
