import path from 'path';
import { promises as fs } from 'fs';

// Root of the OpenClaw installation
export const OPENCLAW_ROOT = process.env.OPENCLAW_ROOT || '/home/ollie/.openclaw';

// Project info returned by /api/projects
export interface ProjectInfo {
  id: string;
  name: string;
  status: 'active' | 'idle' | 'error';
}

/**
 * Resolves the workspace state file path for a given project.
 * Mirrors Python's get_state_path() convention from Phase 11.
 * Path: <OPENCLAW_ROOT>/workspace/.openclaw/<projectId>/workspace-state.json
 */
export function resolveStateFilePath(projectId: string): string {
  return path.join(OPENCLAW_ROOT, 'workspace', '.openclaw', projectId, 'workspace-state.json');
}

/**
 * Resolves the projects directory path.
 */
export function resolveProjectsDir(): string {
  return path.join(OPENCLAW_ROOT, 'projects');
}

/**
 * Returns the first alphabetically-sorted project ID that has a project.json,
 * skipping entries starting with '_'. Returns null if no projects found.
 */
export async function getDefaultProject(): Promise<string | null> {
  try {
    const projectsDir = resolveProjectsDir();
    const entries = await fs.readdir(projectsDir, { withFileTypes: true });

    const candidates: string[] = [];
    for (const entry of entries) {
      if (!entry.isDirectory() || entry.name.startsWith('_')) continue;
      const projectJsonPath = path.join(projectsDir, entry.name, 'project.json');
      try {
        await fs.access(projectJsonPath);
        candidates.push(entry.name);
      } catch {
        // No project.json — skip
      }
    }

    candidates.sort();
    return candidates.length > 0 ? candidates[0] : null;
  } catch {
    return null;
  }
}
