/**
 * Jarvis Protocol TypeScript Types
 *
 * Type definitions matching the Jarvis Protocol schema from orchestration/state_engine.py
 * Includes Zod schemas for runtime validation.
 */

import { z } from 'zod';

// ============================================================================
// Zod Schemas
// ============================================================================

export const ActivityEntrySchema = z.object({
  timestamp: z.number(),
  status: z.string(),
  entry: z.string(),
});

export const TaskSchema = z.object({
  status: z.enum(['pending', 'in_progress', 'completed', 'failed']),
  skill_hint: z.string().optional(),
  activity_log: z.array(ActivityEntrySchema),
  created_at: z.number(),
  updated_at: z.number(),
  metadata: z.record(z.string(), z.any()).optional(),
});

export const JarvisStateSchema = z.object({
  version: z.union([z.string(), z.number()]),
  protocol: z.literal('jarvis').optional(),
  tasks: z.record(z.string(), TaskSchema),
  metadata: z.object({
    created_at: z.number().optional(),
    last_updated: z.number(),
  }),
});

// ============================================================================
// TypeScript Types (inferred from Zod schemas)
// ============================================================================

export type ActivityEntry = z.infer<typeof ActivityEntrySchema>;
export type Task = z.infer<typeof TaskSchema>;
export type JarvisState = z.infer<typeof JarvisStateSchema>;

// ============================================================================
// Validation Functions
// ============================================================================

/**
 * Validates and parses unknown data as JarvisState.
 * Throws ZodError on invalid shape.
 */
export function parseJarvisState(data: unknown): JarvisState {
  return JarvisStateSchema.parse(data);
}

/**
 * Safely parses unknown data as JarvisState.
 * Returns { success: true, data } or { success: false, error }.
 */
export function safeParseJarvisState(data: unknown):
  | { success: true; data: JarvisState }
  | { success: false; error: z.ZodError } {
  const result = JarvisStateSchema.safeParse(data);
  if (result.success) {
    return { success: true, data: result.data };
  }
  return { success: false, error: result.error };
}
