/**
 * Agent Hierarchy and Metrics Derivation
 *
 * Builds agent hierarchy from openclaw.json and derives metrics from workspace-state.json
 */

import { JarvisState, Task } from './jarvis';

// ============================================================================
// Types
// ============================================================================

export type AgentStatus = 'idle' | 'working' | 'error' | 'offline';

export interface AgentNode {
  id: string;
  name: string;
  level: 1 | 2 | 3;
  status: AgentStatus;
  currentTask?: string;
  reports_to?: string | null;
  container_name?: string;
}

export interface SwarmMetrics {
  totalByTier: {
    L1: number;
    L2: number;
    L3: number;
  };
  active: number;
  idle: number;
  errored: number;
  totalTasks: number;
  completedTasks: number;
  failedTasks: number;
}

// ============================================================================
// OpenClaw Agent Config Types
// ============================================================================

interface OpenClawAgent {
  id: string;
  name: string;
  level?: number;
  reports_to?: string | null;
  workspace?: string;
  sandbox?: {
    mode?: string;
  };
}

interface OpenClawConfig {
  agents?: {
    list?: OpenClawAgent[];
  };
}

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Determine agent status based on task states
 * - 'working': has in_progress tasks
 * - 'error': has failed tasks
 * - 'idle': no tasks or all completed
 * - 'offline': container not found (detected via metadata)
 */
function deriveAgentStatus(agentId: string, state: JarvisState): AgentStatus {
  const taskEntries = Object.entries(state.tasks) as [string, Task][];
  const tasks = taskEntries.filter(([, task]) => task.metadata?.agent_id === agentId || String(task.metadata?.container_name || '').includes(agentId));

  if (tasks.length === 0) {
    return 'idle';
  }

  const hasInProgress = tasks.some(([, task]) => task.status === 'in_progress');
  const hasFailed = tasks.some(([, task]) => task.status === 'failed');
  const allCompleted = tasks.every(([, task]) => task.status === 'completed');

  if (hasInProgress) return 'working';
  if (hasFailed) return 'error';
  if (allCompleted) return 'idle';

  return 'idle';
}

/**
 * Find the current active task for an agent
 */
function findCurrentTask(agentId: string, state: JarvisState): string | undefined {
  const taskEntries = Object.entries(state.tasks) as [string, Task][];
  const inProgressTask = taskEntries.find(
    ([, task]) =>
      task.status === 'in_progress' &&
      (task.metadata?.agent_id === agentId || String(task.metadata?.container_name || '').includes(agentId))
  );

  if (inProgressTask) {
    const [taskId, task] = inProgressTask;
    const latestActivity = task.activity_log[task.activity_log.length - 1];
    return latestActivity?.entry || `Task ${taskId}`;
  }

  return undefined;
}

// ============================================================================
// Main Functions
// ============================================================================

/**
 * Build agent hierarchy from openclaw.json agents list correlated with state
 */
export function buildAgentHierarchy(
  agents: OpenClawAgent[],
  state: JarvisState
): AgentNode[] {
  // Build ID set for referent validation
  const agentIds = new Set(agents.map((a) => a.id));

  // Validate reports_to references (warn on missing referent)
  agents.forEach((agent) => {
    if (agent.reports_to && !agentIds.has(agent.reports_to)) {
      console.warn(
        `[hierarchy] Agent '${agent.id}' reports_to '${agent.reports_to}' which is not in the agents list`
      );
    }
  });

  // Detect circular chains via path-length guard
  agents.forEach((agent) => {
    let current = agent.reports_to;
    let steps = 0;
    while (current && steps <= agents.length) {
      const parent = agents.find((a) => a.id === current);
      current = parent?.reports_to ?? null;
      steps++;
    }
    if (steps > agents.length) {
      console.warn(`[hierarchy] Circular reports_to chain detected starting from '${agent.id}'`);
    }
  });

  return agents.map((agent) => {
    const level = (agent.level || 1) as 1 | 2 | 3;
    const status = deriveAgentStatus(agent.id, state);
    const currentTask = findCurrentTask(agent.id, state);

    // Determine container name from metadata or construct it
    const taskValues = Object.values(state.tasks) as Task[];
    const foundTask = taskValues.find((task) => task.metadata?.agent_id === agent.id);
    const containerName = String(foundTask?.metadata?.container_name ||
      `openclaw-${level === 3 ? 'l3-' : ''}${agent.id}`);

    return {
      id: agent.id,
      name: agent.name,
      level,
      status,
      currentTask,
      reports_to: agent.reports_to,
      container_name: containerName,
    };
  });
}

/**
 * Derive swarm metrics from agent nodes and state
 */
export function deriveSwarmMetrics(
  agents: AgentNode[],
  state: JarvisState
): SwarmMetrics {
  const totalByTier = {
    L1: agents.filter((a) => a.level === 1).length,
    L2: agents.filter((a) => a.level === 2).length,
    L3: agents.filter((a) => a.level === 3).length,
  };

  const active = agents.filter((a) => a.status === 'working').length;
  const idle = agents.filter((a) => a.status === 'idle').length;
  const errored = agents.filter((a) => a.status === 'error').length;

  const allTasks = Object.values(state.tasks) as Task[];
  const totalTasks = allTasks.length;
  const completedTasks = allTasks.filter((t: Task) => t.status === 'completed').length;
  const failedTasks = allTasks.filter((t: Task) => t.status === 'failed').length;

  return {
    totalByTier,
    active,
    idle,
    errored,
    totalTasks,
    completedTasks,
    failedTasks,
  };
}

export type { OpenClawAgent, OpenClawConfig };
