import path from 'path';
import { promises as fs } from 'fs';
import { NextRequest, NextResponse } from 'next/server';
import { parseJarvisState, JarvisState } from '@/lib/jarvis';
import { buildAgentHierarchy, deriveSwarmMetrics, AgentNode, SwarmMetrics, OpenClawAgent } from '@/lib/metrics';
import { resolveStateFilePath, resolveProjectsDir, getDefaultProject } from '@/lib/projects';

// Cache for parsed state with TTL — keyed by projectId to prevent cross-project bleed
interface CachedState {
  state: JarvisState;
  agents: unknown[];
  agentNodes: AgentNode[];
  metrics: SwarmMetrics;
  mtime: number;
  timestamp: number;
}

const stateCache = new Map<string, CachedState>();
const CACHE_TTL_MS = 500; // 500ms TTL as per plan requirements

// Global config path — openclaw.json is not per-project
const DEFAULT_OPENCLAW_CONFIG = '/home/ollie/.openclaw/openclaw.json';

async function readStateFile(projectId: string): Promise<{ data: string; mtime: number }> {
  const stateFilePath = resolveStateFilePath(projectId);
  const [data, stats] = await Promise.all([
    fs.readFile(stateFilePath, 'utf8'),
    fs.stat(stateFilePath),
  ]);
  return { data, mtime: stats.mtimeMs };
}

async function readOpenClawConfig(): Promise<{ agents: unknown[] }> {
  const configPath = process.env.OPENCLAW_CONFIG || DEFAULT_OPENCLAW_CONFIG;
  const data = await fs.readFile(configPath, 'utf8');
  const config = JSON.parse(data);
  return { agents: config.agents?.list || [] };
}

export async function getSwarmState(projectId: string): Promise<{
  agents: AgentNode[];
  metrics: SwarmMetrics;
  state: JarvisState;
  lastUpdated: string;
}> {
  const now = Date.now();

  // Check cache validity
  const cached = stateCache.get(projectId);
  if (cached && now - cached.timestamp < CACHE_TTL_MS) {
    return {
      agents: cached.agentNodes,
      metrics: cached.metrics,
      state: cached.state,
      lastUpdated: new Date(cached.mtime).toISOString(),
    };
  }

  // Read state file and check mtime
  const { data: stateData, mtime } = await readStateFile(projectId);

  // If we have a cache with the same mtime, use it
  if (cached && cached.mtime === mtime) {
    stateCache.set(projectId, { ...cached, timestamp: now });
    return {
      agents: cached.agentNodes,
      metrics: cached.metrics,
      state: cached.state,
      lastUpdated: new Date(mtime).toISOString(),
    };
  }

  // Parse and validate state
  const rawState = JSON.parse(stateData);
  const state = parseJarvisState(rawState);

  // Read agent config
  const { agents: agentConfigs } = await readOpenClawConfig();

  // Build hierarchy and metrics
  const agentNodes = buildAgentHierarchy(agentConfigs as OpenClawAgent[], state);
  const metrics = deriveSwarmMetrics(agentNodes, state);

  // Update per-project cache
  stateCache.set(projectId, {
    state,
    agents: agentConfigs,
    agentNodes,
    metrics,
    mtime,
    timestamp: now,
  });

  return {
    agents: agentNodes,
    metrics,
    state,
    lastUpdated: new Date(mtime).toISOString(),
  };
}

/**
 * Returns an empty-but-valid swarm state for projects that exist but have no state file yet.
 */
export function emptySwarmState(): {
  agents: AgentNode[];
  metrics: SwarmMetrics;
  state: JarvisState;
  lastUpdated: string;
} {
  const state = parseJarvisState({ version: '1.0', tasks: {}, metadata: { last_updated: Date.now() } });
  const metrics = deriveSwarmMetrics([], state);
  return {
    agents: [],
    metrics,
    state,
    lastUpdated: new Date().toISOString(),
  };
}

export async function GET(request: NextRequest) {
  try {
    const searchParams = new URL(request.url).searchParams;
    let projectId = searchParams.get('project');

    // Fallback to first available project if no param provided
    if (!projectId) {
      projectId = await getDefaultProject();
    }

    if (!projectId) {
      return NextResponse.json({ error: 'No projects found' }, { status: 404 });
    }

    // Validate project existence: check project.json in projects/<id>/
    const projectJsonPath = path.join(resolveProjectsDir(), projectId, 'project.json');
    try {
      await fs.access(projectJsonPath);
    } catch {
      return NextResponse.json(
        { error: 'Project not found', project: projectId },
        { status: 404 }
      );
    }

    // Attempt to read state — return empty state if state file doesn't exist yet
    try {
      const swarmState = await getSwarmState(projectId);
      return NextResponse.json(swarmState);
    } catch (stateError) {
      const msg = stateError instanceof Error ? stateError.message : String(stateError);
      // If state file simply doesn't exist, return empty state (not an error)
      if (msg.includes('ENOENT') || msg.includes('no such file')) {
        return NextResponse.json(emptySwarmState());
      }
      throw stateError;
    }
  } catch (error) {
    console.error('Error reading swarm state:', error);
    const errorMessage = error instanceof Error ? error.message : String(error);
    return NextResponse.json(
      { error: 'Failed to read swarm state', detail: errorMessage },
      { status: 500 }
    );
  }
}
